import React, { useState, useEffect } from 'react';
import { useClaudeAPI } from '../hooks/useClaudeAPI';
import { useTheme } from '../hooks/useTheme';
import { usePersistentState } from '../hooks/usePersistentState';
import { CopyBtn, ActionBar } from '../components/ActionButtons';

const BRAND = '\n\n— Generated by DeftBrain · deftbrain.com';

const EVENTS = [
  { id: 'work_happy_hour', icon: '🍻', label: 'Work Happy Hour' }, { id: 'dinner_party', icon: '🍽️', label: 'Dinner Party' },
  { id: 'first_date', icon: '💘', label: 'First Date' }, { id: 'networking', icon: '🤝', label: 'Networking Event' },
  { id: 'wedding', icon: '💒', label: 'Wedding / Reception' }, { id: 'family_holiday', icon: '🦃', label: 'Family Holiday' },
  { id: 'housewarming', icon: '🏠', label: 'Housewarming' }, { id: 'kids_event', icon: '👶', label: 'Kid\'s Event' },
  { id: 'reunion', icon: '🎓', label: 'Reunion' }, { id: 'conference', icon: '🎤', label: 'Conference' },
  { id: 'gym_class', icon: '🏋️', label: 'Gym / Class' }, { id: 'new_job', icon: '🆕', label: 'New Job' },
];
const QUICK_SCENARIOS = [
  { id: 'elevator', icon: '🏢', label: 'Elevator' }, { id: 'uber', icon: '🚗', label: 'Uber / Taxi' },
  { id: 'waiting_room', icon: '🪑', label: 'Waiting Room' }, { id: 'hairdresser', icon: '💇', label: 'Hairdresser' },
  { id: 'neighbors', icon: '🏡', label: 'Ran Into Neighbor' }, { id: 'checkout_line', icon: '🛒', label: 'Checkout Line' },
  { id: 'dog_park', icon: '🐕', label: 'Dog Park' }, { id: 'break_room', icon: '☕', label: 'Break Room' },
  { id: 'flight', icon: '✈️', label: 'Airplane Seatmate' }, { id: 'gym', icon: '🏋️', label: 'Gym' },
];
const RELATIONSHIPS = [
  { id: 'stranger', icon: '👤', label: 'Stranger' }, { id: 'acquaintance', icon: '🙂', label: 'Acquaintance' },
  { id: 'coworker', icon: '💼', label: 'Coworker' }, { id: 'boss', icon: '👔', label: 'Boss' },
  { id: 'date', icon: '💕', label: 'Date / Crush' }, { id: 'in_laws', icon: '👪', label: 'In-Laws' },
  { id: 'old_friend', icon: '🫂', label: 'Old Friend' }, { id: 'new_friend', icon: '✨', label: 'New Friend' },
  { id: 'parent_peer', icon: '👶', label: 'Other Parent' },
];
const COMFORT = [
  { id: 'panicking', icon: '😰', label: 'Panicking' }, { id: 'nervous', icon: '😬', label: 'Nervous' },
  { id: 'slightly_awkward', icon: '😅', label: 'A little awkward' }, { id: 'fine', icon: '🙂', label: 'Mostly fine' },
];
const ENERGY_COLORS = {
  low_key: ['bg-sky-900/30 text-sky-300', 'bg-sky-100 text-sky-700'], warm: ['bg-amber-900/30 text-amber-300', 'bg-amber-100 text-amber-700'],
  playful: ['bg-cyan-900/30 text-cyan-300', 'bg-cyan-100 text-cyan-700'], bold: ['bg-red-900/30 text-red-300', 'bg-red-100 text-red-700'],
  confident: ['bg-cyan-900/30 text-cyan-300', 'bg-cyan-100 text-cyan-700'],
};

const RoomReader = ({ tool }) => {
  const { callToolEndpoint, loading } = useClaudeAPI();
  const { isDark } = useTheme();

  useEffect(() => {
    const handler = (e) => {
      const tag = document.activeElement?.tagName;
      if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
      if (e.key === 'Enter' && (e.metaKey || e.ctrlKey) && !loading) handleRecovery();
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [loading]);


  const linkStyle = isDark
    ? 'text-cyan-400 hover:text-cyan-300 underline underline-offset-2'
    : 'text-cyan-600 hover:text-cyan-700 underline underline-offset-2';

  const c = {
    card:          isDark ? 'bg-zinc-800' : 'bg-white',
    cardAlt:       isDark ? 'bg-zinc-700/50' : 'bg-slate-50',
    input:         isDark ? 'bg-zinc-900 border-zinc-600 text-zinc-100 placeholder-zinc-400 focus:border-cyan-500 focus:ring-cyan-500/20' : 'bg-white border-gray-300 text-gray-900 placeholder-gray-400 focus:border-cyan-500 focus:ring-cyan-100',
    text:          isDark ? 'text-zinc-50' : 'text-gray-900',
    textSecondary: isDark ? 'text-zinc-300' : 'text-gray-600',
    textMuted:     isDark ? 'text-zinc-500' : 'text-gray-400',
    labelText:     isDark ? 'text-zinc-200' : 'text-gray-700',
    accentTxt:     isDark ? 'text-cyan-400' : 'text-cyan-600',
    btnPrimary:    isDark ? 'bg-cyan-600 hover:bg-cyan-500 text-white' : 'bg-cyan-600 hover:bg-cyan-700 text-white',
    btnSecondary:  isDark ? 'bg-zinc-700 hover:bg-zinc-600 text-zinc-200' : 'bg-gray-100 hover:bg-gray-200 text-gray-700',
    border:        isDark ? 'border-zinc-700' : 'border-gray-200',
    success:       isDark ? 'bg-emerald-900/20 border-emerald-700 text-emerald-200' : 'bg-emerald-50 border-emerald-300 text-emerald-800',
    warning:       isDark ? 'bg-amber-900/20 border-amber-700 text-amber-200' : 'bg-amber-50 border-amber-300 text-amber-800',
    danger:        isDark ? 'bg-red-900/20 border-red-700 text-red-200' : 'bg-red-50 border-red-200 text-red-800',
    infoBox:       isDark ? 'bg-sky-900/20 border-sky-700 text-sky-200' : 'bg-sky-50 border-sky-200 text-sky-800',
    successBox:    isDark ? 'bg-emerald-900/20 border-emerald-700' : 'bg-emerald-50 border-emerald-300',
    successTxt:    isDark ? 'text-emerald-300' : 'text-emerald-800',
    warningBox:    isDark ? 'bg-amber-900/20 border-amber-700' : 'bg-amber-50 border-amber-300',
    warningTxt:    isDark ? 'text-amber-300' : 'text-amber-800',
    pillActive:    isDark ? 'border-cyan-500 bg-cyan-900/30 text-cyan-200' : 'border-cyan-600 bg-cyan-100 text-cyan-900',
    pillInactive:  isDark ? 'border-zinc-600 text-zinc-400 hover:border-zinc-500' : 'border-gray-300 text-gray-500 hover:border-gray-400',
  };;

  // ─── Mode + error ───
  const [mode, setMode] = useState('pregame');
  const [error, setError] = useState('');

  // ─── Pre-Game ───
  const [eventType, setEventType] = useState('');
  const [eventDetails, setEventDetails] = useState('');
  const [people, setPeople] = useState('');
  const [concerns, setConcerns] = useState('');
  const [topicsToAvoid, setTopicsToAvoid] = useState('');
  const [comfort, setComfort] = useState('nervous');
  const [preGameResults, setPreGameResults] = useState(null);

  // ─── Quick Read ───
  const [quickScenario, setQuickScenario] = useState('');
  const [quickRelationship, setQuickRelationship] = useState('');
  const [quickResults, setQuickResults] = useState(null);
  const [quickExclude, setQuickExclude] = useState([]);

  // ─── Decoder ───
  const [theyDid, setTheyDid] = useState('');
  const [decodeContext, setDecodeContext] = useState('');
  const [decodeRelationship, setDecodeRelationship] = useState('');
  const [yourConcern, setYourConcern] = useState('');
  const [decodeResults, setDecodeResults] = useState(null);

  // ─── Follow-Up ───
  const [followUpWho, setFollowUpWho] = useState('');
  const [followUpContext, setFollowUpContext] = useState('');
  const [followUpWhat, setFollowUpWhat] = useState('');
  const [followUpGoal, setFollowUpGoal] = useState('');
  const [followUpResults, setFollowUpResults] = useState(null);

  // ─── Debrief ───
  const [debriefEvent, setDebriefEvent] = useState('');
  const [debriefWhat, setDebriefWhat] = useState('');
  const [debriefGood, setDebriefGood] = useState('');
  const [debriefAwkward, setDebriefAwkward] = useState('');
  const [debriefFeeling, setDebriefFeeling] = useState('mixed');
  const [debriefResults, setDebriefResults] = useState(null);

  // ─── Person Prep + Recurring Tracker (v2+v3) ───
  const [personName, setPersonName] = useState('');
  const [personRelationship, setPersonRelationship] = useState('');
  const [personKnow, setPersonKnow] = useState('');
  const [personContext, setPersonContext] = useState('');
  const [personConcern, setPersonConcern] = useState('');
  const [personResults, setPersonResults] = useState(null);
  const [personNoteTopics, setPersonNoteTopics] = useState('');
  const [personNoteBombed, setPersonNoteBombed] = useState('');
  const [personNoteText, setPersonNoteText] = useState('');
  const [personRefreshResults, setPersonRefreshResults] = useState(null);
  const [selectedTrackedPerson, setSelectedTrackedPerson] = useState(null);

  // ─── Group ───
  const [groupSituation, setGroupSituation] = useState('');
  const [groupSize, setGroupSize] = useState('4-6');
  const [groupRole, setGroupRole] = useState('');
  const [groupChallenge, setGroupChallenge] = useState('');
  const [groupResults, setGroupResults] = useState(null);

  // ─── Recovery (v3) ───
  const [recoverySaid, setRecoverySaid] = useState('');
  const [recoveryContext, setRecoveryContext] = useState('');
  const [recoveryRelationship, setRecoveryRelationship] = useState('');
  const [recoveryHowBad, setRecoveryHowBad] = useState('bad');
  const [recoveryResults, setRecoveryResults] = useState(null);

  // ─── Culture Decoder (v3) ───
  const [cultureText, setCultureText] = useState('');
  const [cultureSituation, setCultureSituation] = useState('');
  const [cultureMyBg, setCultureMyBg] = useState('');
  const [cultureConcern, setCultureConcern] = useState('');
  const [cultureResults, setCultureResults] = useState(null);

  // ─── Energy Match (v3) ───
  const [myEnergy, setMyEnergy] = useState('');
  const [roomEnergy, setRoomEnergy] = useState('');
  const [energyContext, setEnergyContext] = useState('');
  const [energyResults, setEnergyResults] = useState(null);

  // ─── Small Talk Ladder (v3) ───
  const [ladderRelationship, setLadderRelationship] = useState('');
  const [ladderContext, setLadderContext] = useState('');
  const [ladderDepth, setLadderDepth] = useState('');
  const [ladderResults, setLadderResults] = useState(null);

  // ─── Social Autopsy (v3) ───
  const [autopsyWhat, setAutopsyWhat] = useState('');
  const [autopsyTimeline, setAutopsyTimeline] = useState('');
  const [autopsyFelt, setAutopsyFelt] = useState('');
  const [autopsyThink, setAutopsyThink] = useState('');
  const [autopsyResults, setAutopsyResults] = useState(null);

  // ─── Persistent ───
  const [playbook, setPlaybook] = usePersistentState('room-reader-playbook', []);
  const [history, setHistory] = usePersistentState('room-reader-history', []);
  const [saved, setSaved] = usePersistentState('room-reader-saved', []);
  const [gamePlans, setGamePlans] = usePersistentState('room-reader-plans', []);
  const [trackedPeople, setTrackedPeople] = usePersistentState('room-reader-people', []);
  const [showPlaybook, setShowPlaybook] = useState(false);
  const [showPlans, setShowPlans] = useState(false);

  // ─── UI ───
  const [expandedSections, setExpandedSections] = useState({});
  const toggleSection = (k) => setExpandedSections(p => ({ ...p, [k]: !p[k] }));

  // ═══ HELPERS ═══
  const addToHistory = (type, label) => setHistory(prev => [{ type, label, preview: String(label).slice(0, 40), timestamp: new Date().toISOString() }, ...prev].slice(0, 6));
  const addToPlaybook = (tactic, context, rating = 4) => setPlaybook(prev => { if (prev.find(p => p.tactic === tactic)) return prev; return [{ tactic, context, rating, timestamp: new Date().toISOString() }, ...prev].slice(0, 30); });
  const saveLine = (line, ctx) => setSaved(prev => { if (prev.find(s => s.line === line)) return prev; return [{ line, context: ctx, timestamp: new Date().toISOString() }, ...prev].slice(0, 50); });
  const isSaved = (line) => saved.some(s => s.line === line);
  const saveGamePlan = (label, data) => setGamePlans(prev => [{ label, data, timestamp: new Date().toISOString() }, ...prev].slice(0, 6));

  // Person tracker helpers
  const addTrackedPerson = (name, rel) => {
    if (trackedPeople.find(p => p.name === name)) return;
    setTrackedPeople(prev => [...prev, { name, relationship: rel, notes: [], created: new Date().toISOString() }]);
  };
  const addPersonNote = (personIdx) => {
    if (!personNoteText.trim() && !personNoteTopics.trim()) return;
    setTrackedPeople(prev => {
      const u = [...prev]; u[personIdx] = { ...u[personIdx], notes: [{ topicsWorked: personNoteTopics, topicsBombed: personNoteBombed, notes: personNoteText, date: new Date().toLocaleDateString() }, ...u[personIdx].notes].slice(0, 20) };
      return u;
    });
    setPersonNoteTopics(''); setPersonNoteBombed(''); setPersonNoteText('');
  };

  // Cheat sheet builder
  const buildCheatSheet = (plan) => {
    let t = `📋 CHEAT SHEET\n`;
    if (plan.vibe_check) t += `\n🧠 ${plan.vibe_check.read}\n💡 ${plan.vibe_check.comfort_hack}\n`;
    plan.conversation_starters?.slice(0, 3).forEach((s, i) => { t += `\n${i + 1}. "${s.line}"\n`; });
    plan.openers?.slice(0, 3).forEach((s, i) => { t += `\n${i + 1}. "${s.line}"\n`; });
    if (plan.pep_talk) t += `\n💚 ${plan.pep_talk}`;
    if (plan.overall_strategy) t += `\n🎯 ${plan.overall_strategy}`;
    return t + BRAND;
  };

  // ═══ API HANDLERS (v2 preserved) ═══
  const handlePreGame = async () => { const el = EVENTS.find(e => e.id === eventType)?.label || eventDetails?.trim(); if (!el) { setError('Pick an event type or describe the situation.'); return; } setError(''); const data = await callToolEndpoint('room-reader', { eventType: el, eventDetails, people, concerns, topicsToAvoid, comfort, playbook }); if (data) { setPreGameResults(data); addToHistory('pregame', el); } };
  const handleQuickRead = async (refresh = false) => { if (!quickScenario) { setError('Tap a scenario.'); return; } setError(''); const sl = QUICK_SCENARIOS.find(s => s.id === quickScenario)?.label || quickScenario; const rl = RELATIONSHIPS.find(r => r.id === quickRelationship)?.label || quickRelationship || 'someone'; const data = await callToolEndpoint('room-reader-quick', { scenario: sl, relationship: rl, playbook, exclude: refresh ? quickExclude : [] }); if (data) { setQuickResults(data); if (refresh && data.line) setQuickExclude(prev => [...prev, data.line]); else setQuickExclude(data.line ? [data.line] : []); addToHistory('quick', `${sl} + ${rl}`); } };
  const handleDecode = async () => { if (!theyDid.trim()) { setError('Describe what they said or did.'); return; } setError(''); const data = await callToolEndpoint('room-reader-decode', { theyDid, context: decodeContext, relationship: decodeRelationship, yourConcern }); if (data) { setDecodeResults(data); addToHistory('decode', theyDid.substring(0, 40)); } };
  const handleFollowUp = async () => { if (!followUpWho.trim() && !followUpContext.trim()) { setError('Who are you following up with?'); return; } setError(''); const data = await callToolEndpoint('room-reader-followup', { who: followUpWho, context: followUpContext, whatHappened: followUpWhat, goal: followUpGoal, playbook }); if (data) { setFollowUpResults(data); addToHistory('followup', followUpWho || followUpContext.substring(0, 30)); } };
  const handleDebrief = async () => { if (!debriefWhat.trim() && !debriefGood.trim() && !debriefAwkward.trim()) { setError('Tell us something about how it went.'); return; } setError(''); const data = await callToolEndpoint('room-reader-debrief', { eventType: debriefEvent, whatHappened: debriefWhat, whatWentWell: debriefGood, whatFeltAwkward: debriefAwkward, overallFeeling: debriefFeeling, playbook }); if (data) { setDebriefResults(data); addToHistory('debrief', debriefEvent || 'event'); data.wins?.forEach(w => { if (w.add_to_playbook) addToPlaybook(w.add_to_playbook, debriefEvent || 'event'); }); } };
  const handlePersonPrep = async () => { if (!personKnow.trim() && !personRelationship.trim()) { setError('Tell us something about this person.'); return; } setError(''); const data = await callToolEndpoint('room-reader-person', { personName, relationship: personRelationship, whatYouKnow: personKnow, context: personContext, yourConcern: personConcern, playbook }); if (data) { setPersonResults(data); addToHistory('person', personName || personRelationship || 'someone'); } };
  const handleGroup = async () => { if (!groupSituation.trim() && !groupChallenge.trim()) { setError('Describe the group situation.'); return; } setError(''); const data = await callToolEndpoint('room-reader-group', { situation: groupSituation, groupSize, yourRole: groupRole, challenge: groupChallenge, playbook }); if (data) { setGroupResults(data); addToHistory('group', groupSituation.substring(0, 40) || 'group'); } };

  // ═══ API HANDLERS (v3 new) ═══
  const handleRecovery = async () => { if (!recoverySaid.trim()) { setError('What did you say?'); return; } setError(''); const data = await callToolEndpoint('room-reader-recover', { whatYouSaid: recoverySaid, context: recoveryContext, relationship: recoveryRelationship, howBad: recoveryHowBad }); if (data) { setRecoveryResults(data); addToHistory('recovery', recoverySaid.substring(0, 30)); } };
  const handleCulture = async () => { if (!cultureText.trim() && !cultureSituation.trim()) { setError('Describe the cultural context.'); return; } setError(''); const data = await callToolEndpoint('room-reader-culture', { culture: cultureText, situation: cultureSituation, myBackground: cultureMyBg, specificConcern: cultureConcern }); if (data) { setCultureResults(data); addToHistory('culture', cultureText || cultureSituation.substring(0, 30)); } };
  const handleEnergy = async () => { if (!myEnergy.trim() || !roomEnergy.trim()) { setError('Describe both energies.'); return; } setError(''); const data = await callToolEndpoint('room-reader-energy', { myEnergy, roomEnergy, context: energyContext }); if (data) { setEnergyResults(data); addToHistory('energy', `${myEnergy} vs ${roomEnergy}`); } };
  const handleLadder = async () => { setError(''); const data = await callToolEndpoint('room-reader-ladder', { relationship: ladderRelationship, context: ladderContext, currentDepth: ladderDepth }); if (data) { setLadderResults(data); addToHistory('ladder', ladderRelationship || 'conversation'); } };
  const handleAutopsy = async () => { if (!autopsyWhat.trim()) { setError('Describe what happened.'); return; } setError(''); const data = await callToolEndpoint('room-reader-autopsy', { whatHappened: autopsyWhat, timeline: autopsyTimeline, howYouFelt: autopsyFelt, whatYouThinkWentWrong: autopsyThink, playbook }); if (data) { setAutopsyResults(data); addToHistory('autopsy', autopsyWhat.substring(0, 30)); if (data.next_time?.add_to_playbook) addToPlaybook(data.next_time.add_to_playbook, 'autopsy'); } };
  const handlePersonRefresh = async (person) => { if (!person.notes?.length) { setError('Log at least one interaction first.'); return; } setError(''); const data = await callToolEndpoint('room-reader-person-refresh', { personName: person.name, relationship: person.relationship, notes: person.notes, nextContext: personContext, playbook }); if (data) { setPersonRefreshResults(data); addToHistory('person-refresh', person.name); } };

  // ═══ TEXT BUILDER ═══
  const buildPreGameText = () => { if (!preGameResults) return ''; const r = preGameResults; let t = `🧠 Room Reader: Pre-Game\n\n`; if (r.vibe_check) t += `${r.vibe_check.read}\n✨ ${r.vibe_check.your_superpower}\n\n`; r.conversation_starters?.forEach((s, i) => { t += `${i + 1}. "${s.line}" (${s.energy})\n`; }); if (r.pep_talk) t += `\n💚 ${r.pep_talk}`; return t + BRAND; };

  // ═══ SUB-COMPONENTS ═══
  const MODES = [
    { id: 'pregame', icon: '🎯', label: 'Pre-Game' }, { id: 'quick', icon: '⚡', label: 'Quick' },
    { id: 'recovery', icon: '🆘', label: 'Recovery' }, { id: 'person', icon: '👤', label: 'Person' },
    { id: 'group', icon: '👥', label: 'Group' }, { id: 'energy', icon: '🔋', label: 'Energy' },
    { id: 'ladder', icon: '🪜', label: 'Depth' }, { id: 'culture', icon: '🌍', label: 'Culture' },
    { id: 'decode', icon: '🔍', label: 'Decoder' }, { id: 'followup', icon: '💬', label: 'Follow-Up' },
    { id: 'debrief', icon: '📝', label: 'Debrief' }, { id: 'autopsy', icon: '🔬', label: 'Autopsy' },
  ];

  const TileGrid = ({ items, selected, onSelect }) => <div className="flex flex-wrap gap-2">{items.map(item => <button key={item.id} onClick={() => onSelect(item.id)} className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors border ${selected === item.id ? (isDark ? 'bg-cyan-600 text-white border-cyan-500' : 'bg-cyan-600 text-white border-cyan-600') : `${c.btnInactive} ${c.border}`}`}><span className="mr-1">{item.icon}</span> {item.label}</button>)}</div>;

  const ConvoLine = ({ label, emoji, text, accent = false, onSave }) => <div className={`${accent ? c.warningBox : c.quoteBg} border rounded-lg p-3`}><div className="flex items-start justify-between gap-2"><div className="flex-1"><p className={`text-xs font-bold ${accent ? c.accentTxt : c.textMuteded} mb-1`}>{emoji} {label}</p><p className={`text-sm ${accent ? `font-semibold ${c.text}` : `${c.textSecondaryondary} italic`}`}>"{text}"</p></div><div className="flex gap-1 flex-shrink-0">{onSave && <button onClick={() => onSave(text)} className={`text-xs px-1.5 py-1 rounded ${isSaved(text) ? (isDark ? 'text-amber-300' : 'text-amber-600') : c.textMuteded}`}>{isSaved(text) ? '⭐' : '☆'}</button>}<CopyBtn content={text + BRAND} label="" /></div></div></div>;

  const StarterCard = ({ s, i, saveCtx }) => { const ek = `starter-${i}`; const isOpen = expandedSections[ek]; const ec = ENERGY_COLORS[s.energy] || ENERGY_COLORS.warm; return <div className={`${c.cardAlt} border ${c.border} rounded-lg overflow-hidden`}><div className="p-4 space-y-2"><div className="flex items-center gap-2 flex-wrap"><span className={`text-xs font-bold px-2 py-0.5 rounded-full ${isDark ? ec[0] : ec[1]}`}>{s.energy}</span>{s.best_for && <span className={`text-xs ${c.textMuteded}`}>→ {s.best_for}</span>}</div><ConvoLine label="You say" emoji="🗣️" text={s.line} accent onSave={(t) => saveLine(t, saveCtx)} /><p className={`text-xs ${c.textMuteded}`}>{s.works_because || s.why}</p>{(s.if_they_respond || s.flow) && <button onClick={() => toggleSection(ek)} className={`text-xs font-bold ${c.accentTxt}`}>{isOpen ? '▲ Hide flow' : '▼ See how it plays out →'}</button>}</div>{isOpen && <div className={`px-4 pb-4 space-y-2 border-t ${c.border} pt-3`}>{(s.if_they_respond || s.flow) && <ConvoLine label="How it flows" emoji="↔️" text={s.if_they_respond || s.flow} />}{s.if_it_falls_flat && <div className={`${c.warning} border rounded-lg p-3`}><p className="text-xs">🛡️ <strong>If it falls flat:</strong> {s.if_it_falls_flat}</p></div>}</div>}</div>; };

  const Section = ({ id, title, children }) => <div className={`${c.card} border ${c.border} rounded-xl overflow-hidden`}><button onClick={() => toggleSection(id)} className="w-full p-4 flex items-center justify-between"><h3 className={`font-bold ${c.text}`}>{title}</h3><span>{expandedSections[id] ? '▲' : '▼'}</span></button>{expandedSections[id] && <div className={`px-4 pb-4 border-t ${c.border} pt-3 space-y-2`}>{children}</div>}</div>;

  const InputCard = ({ title, subtitle, children, onSubmit, btnLabel, btnIcon }) => <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-4`}><h3 className={`font-bold ${c.text}`}>{title}</h3>{subtitle && <p className={`text-sm ${c.textMuteded}`}>{subtitle}{playbook.length > 0 && <span className={c.accentTxt}> 📚 Playbook active.</span>}</p>}{children}<button onClick={onSubmit} disabled={loading} className={`w-full py-3 rounded-xl font-bold text-sm ${c.btnPrimary} disabled:opacity-50`}>{loading ? <span className="inline-block animate-spin">{tool?.icon ?? '⚙️'}</span> : `${btnIcon || ''} ${btnLabel}`}</button></div>;

  // ═══ RENDER ═══

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      {/* Mode Tabs */}
      <div className="flex flex-wrap gap-1.5">
        {MODES.map(m => <button key={m.id} onClick={() => { setMode(m.id); setError(''); }} className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${mode === m.id ? c.btnActive : c.btnInactive}`}><span className="mr-1">{m.icon}</span> {m.label}</button>)}
        {[['showPlaybook', setShowPlaybook, showPlaybook, '📚', `Playbook${playbook.length ? ` (${playbook.length})` : ''}`], ['showPlans', setShowPlans, showPlans, '📋', `Plans${gamePlans.length ? ` (${gamePlans.length})` : ''}`]].map(([k, fn, val, ico, lbl]) => <button key={k} onClick={() => fn(!val)} className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${val ? c.btnActive : c.btnInactive}`}><span className="mr-1">{ico}</span> {lbl}</button>)}
      </div>

      {/* ─── Playbook Panel ─── */}
      {showPlaybook && <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-3`}>
        <h3 className={`font-bold ${c.text}`}>📚 Your Social Playbook</h3>
        <p className={`text-xs ${c.textMuteded}`}>Auto-built from debriefs + autopsies. Shapes suggestions in every mode.</p>
        {playbook.length === 0 ? <p className={`text-sm ${c.textMuteded}`}>Complete a debrief or autopsy to start building.</p> : playbook.map((p, i) => <div key={i} className={`${c.cardAlt} rounded-lg p-3 flex items-start justify-between`}><div><p className={`text-sm font-medium ${c.text}`}>💡 {p.tactic}</p><p className={`text-xs ${c.textMuteded}`}>{p.context}</p></div><button onClick={() => setPlaybook(prev => prev.filter((_, idx) => idx !== i))} className={`text-xs ${c.textMuteded}`}>✕</button></div>)}
        {saved.length > 0 && <><h4 className={`font-bold text-sm ${c.text} mt-4`}>⭐ Saved Lines ({saved.length})</h4>{saved.slice(0, 10).map((s, i) => <div key={i} className={`${c.cardAlt} rounded-lg p-2 flex items-center justify-between`}><div><p className={`text-sm ${c.textSecondaryondary} italic`}>"{s.line}"</p><p className={`text-xs ${c.textMuteded}`}>{s.context}</p></div><button onClick={() => setSaved(prev => prev.filter((_, idx) => idx !== i))} className={`text-xs ${c.textMuteded}`}>✕</button></div>)}</>}
        {trackedPeople.length > 0 && <><h4 className={`font-bold text-sm ${c.text} mt-4`}>👤 Tracked People ({trackedPeople.length})</h4>{trackedPeople.map((tp, i) => <div key={i} className={`${c.cardAlt} rounded-lg p-2 flex items-center justify-between`}><span className={`text-sm ${c.text}`}>{tp.name} ({tp.relationship}) — {tp.notes.length} notes</span><button onClick={() => setTrackedPeople(prev => prev.filter((_, idx) => idx !== i))} className={`text-xs ${c.textMuteded}`}>✕</button></div>)}</>}
      </div>}

      {/* ─── Plans Panel ─── */}
      {showPlans && <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-3`}>
        <h3 className={`font-bold ${c.text}`}>📋 Saved Game Plans</h3>
        {gamePlans.length === 0 ? <p className={`text-sm ${c.textMuteded}`}>Save a Pre-Game or Person Prep to store it here.</p> : gamePlans.map((gp, i) => <div key={i} className={`${c.cardAlt} border ${c.border} rounded-lg p-4 space-y-2`}><div className="flex items-center justify-between"><div><p className={`text-sm font-bold ${c.text}`}>📋 {gp.label}</p><p className={`text-xs ${c.textMuteded}`}>{new Date(gp.timestamp).toLocaleDateString()}</p></div><div className="flex gap-2"><CopyBtn content={buildCheatSheet(gp.data)} label="📱 Cheat Sheet" /><button onClick={() => setGamePlans(prev => prev.filter((_, idx) => idx !== i))} className={`text-xs ${c.textMuteded}`}>🗑️</button></div></div><button onClick={() => toggleSection(`plan-${i}`)} className={`text-xs font-bold ${c.accentTxt}`}>{expandedSections[`plan-${i}`] ? '▲ Collapse' : '▼ Expand'}</button>{expandedSections[`plan-${i}`] && <div className="space-y-2 mt-2">{gp.data.vibe_check && <div className={`${c.warningBox} border rounded-lg p-3`}><p className={`text-sm ${c.text}`}>{gp.data.vibe_check.read}</p></div>}{(gp.data.conversation_starters || gp.data.openers)?.slice(0, 3).map((s, j) => <ConvoLine key={j} label={`Line ${j + 1}`} emoji="🗣️" text={s.line} accent />)}{gp.data.pep_talk && <div className={`${c.success} border rounded-lg p-3`}><p className="text-sm">💚 {gp.data.pep_talk}</p></div>}{gp.data.overall_strategy && <div className={`${c.purpleBg} border rounded-lg p-3`}><p className="text-sm">{gp.data.overall_strategy}</p></div>}</div>}</div>)}
      </div>}

      {/* ═══ PRE-GAME ═══ */}
      {mode === 'pregame' && <>{<InputCard title="🎯 Pre-Game Prep" subtitle="What's the event?" onSubmit={handlePreGame} btnLabel="Generate Game Plan" btnIcon="🎯"><TileGrid items={EVENTS} selected={eventType} onSelect={setEventType} /><textarea value={eventDetails} onChange={e => setEventDetails(e.target.value)} placeholder="Details — 'My girlfriend's birthday dinner, 12 people, I only know her'" rows={2} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={people} onChange={e => setPeople(e.target.value)} placeholder="Who'll be there? (optional)" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={concerns} onChange={e => setConcerns(e.target.value)} placeholder="Your concerns (optional)" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={topicsToAvoid} onChange={e => setTopicsToAvoid(e.target.value)} placeholder="Topics to avoid (optional)" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><div className="flex flex-wrap gap-2">{COMFORT.map(cl => <button key={cl.id} onClick={() => setComfort(cl.id)} className={`px-3 py-1.5 rounded-lg text-xs font-medium border ${comfort === cl.id ? c.btnActive : `${c.btnInactive} ${c.border}`}`}><span className="mr-1">{cl.icon}</span> {cl.label}</button>)}</div></InputCard>}{preGameResults && <div className="space-y-4"><button onClick={() => saveGamePlan(EVENTS.find(e => e.id === eventType)?.label || eventDetails?.trim() || 'Event', preGameResults)} className={`w-full py-2 rounded-lg text-xs font-bold ${c.btnSecondaryondary} border ${c.border}`}>📋 Save Plan</button>{preGameResults.vibe_check && <div className={`${c.warningBox} border rounded-xl p-5 space-y-3`}><h3 className={`font-bold ${c.accentTxt}`}>🧠 Vibe Check</h3><p className={`text-sm ${c.text}`}>{preGameResults.vibe_check.read}</p><div className={`${c.success} border rounded-lg p-3`}><p className="text-sm">✨ {preGameResults.vibe_check.your_superpower}</p></div><div className={`${c.infoBox} border rounded-lg p-3`}><p className="text-sm">💡 {preGameResults.vibe_check.comfort_hack}</p></div></div>}{preGameResults.conversation_starters?.length > 0 && <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-3`}><h3 className={`font-bold ${c.text}`}>💬 Starters</h3>{preGameResults.conversation_starters.map((s, i) => <StarterCard key={i} s={s} i={i} saveCtx={eventDetails || eventType} />)}</div>}{preGameResults.people_map?.length > 0 && <Section id="people" title="👥 People Map">{preGameResults.people_map.map((p, i) => <div key={i} className={`${c.cardAlt} rounded-lg p-3 space-y-2`}><p className={`text-sm font-bold ${c.text}`}>{p.who}</p><ConvoLine label="Opener" emoji="💬" text={p.opener} accent onSave={(t) => saveLine(t, p.who)} />{p.watch_for && <p className={`text-xs ${c.textMuteded}`}>👀 {p.watch_for}</p>}</div>)}</Section>}{preGameResults.body_language && <Section id="body" title="🧍 Body Language"><p className={`text-sm ${c.textSecondaryondary}`}>🚪 {preGameResults.body_language.arrival}</p><p className={`text-sm ${c.textSecondaryondary}`}>🧑‍🤝‍🧑 {preGameResults.body_language.during}</p><div className={`${c.success} border rounded-lg p-3`}><p className="text-sm">✨ {preGameResults.body_language.secret_weapon}</p></div></Section>}{preGameResults.exit_toolkit?.length > 0 && <Section id="exits" title="🚪 Exits">{preGameResults.exit_toolkit.map((e, i) => <div key={i} className={`${c.quoteBg} border rounded-lg p-3`}><p className={`text-xs ${c.textMuteded}`}>{e.scenario}</p><p className={`text-sm ${c.text}`}>"{e.line}"</p><CopyBtn content={e.line + BRAND} label="Copy" /></div>)}</Section>}{preGameResults.worst_case_saves?.length > 0 && <Section id="worst" title="🛟 Worst Case">{preGameResults.worst_case_saves.map((w, i) => <div key={i} className={`${c.warning} border rounded-lg p-3`}><p className="text-sm font-medium">😬 {w.scenario}</p><p className="text-sm">💡 {w.save}</p></div>)}</Section>}{preGameResults.pep_talk && <div className={`${c.success} border rounded-xl p-5`}><p className={`text-sm font-medium ${isDark ? 'text-green-200' : 'text-green-800'}`}>💚 {preGameResults.pep_talk}</p></div>}<ActionBar content={buildPreGameText()} title="Room Reader: Pre-Game" /></div>}</>}

      {/* ═══ QUICK READ ═══ */}
      {mode === 'quick' && <>{<InputCard title="⚡ Quick Read" subtitle="Tap and go. No typing needed." onSubmit={() => handleQuickRead(false)} btnLabel="Read" btnIcon="⚡"><TileGrid items={QUICK_SCENARIOS} selected={quickScenario} onSelect={(id) => { setQuickScenario(id); setQuickExclude([]); setQuickResults(null); }} /><TileGrid items={RELATIONSHIPS} selected={quickRelationship} onSelect={setQuickRelationship} /></InputCard>}{quickResults && <div className="space-y-4"><div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-3`}><ConvoLine label="Say this" emoji="🗣️" text={quickResults.line} accent onSave={(t) => saveLine(t, quickScenario)} /><p className={`text-xs ${c.textMuteded}`}>{quickResults.why_it_works}</p><ConvoLine label="They'll say" emoji="💭" text={quickResults.they_say} /><div className="flex justify-center"><span className={`text-xs ${c.textMuteded}`}>↓</span></div><ConvoLine label="Then you" emoji="🗣️" text={quickResults.you_follow} accent onSave={(t) => saveLine(t, quickScenario)} />{quickResults.if_nothing && <div className={`${c.warning} border rounded-lg p-3`}><p className="text-xs">🛡️ {quickResults.if_nothing}</p></div>}{quickResults.body_tip && <p className={`text-xs ${c.textSecondaryondary}`}>🧍 {quickResults.body_tip}</p>}<button onClick={() => handleQuickRead(true)} disabled={loading} className={`w-full py-2 rounded-lg text-xs font-bold ${c.btnSecondaryondary} border ${c.border}`}>{loading ? <span className="inline-block animate-spin">{tool?.icon ?? '⚙️'}</span> : `🔀 Different one${quickExclude.length ? ` (${quickExclude.length} tried)` : ''}`}</button></div><div className={`${c.infoBox} border rounded-xl p-4`}><p className="text-sm">🤫 <strong>Or don't.</strong> {quickResults.silence_reframe}</p></div></div>}</>}

      {/* ═══ RECOVERY (v3) ═══ */}
      {mode === 'recovery' && <>{<div className={`${c.emergencyBg} border rounded-xl p-5 space-y-4`}><h3 className={`font-bold ${isDark ? 'text-red-200' : 'text-red-800'}`}>🆘 Conversation Recovery</h3><p className={`text-sm ${isDark ? 'text-red-300' : 'text-red-600'}`}>Just said something weird? We'll assess the damage and give you a save.</p><textarea value={recoverySaid} onChange={e => setRecoverySaid(e.target.value)} placeholder="What did you say? (be specific)" rows={2} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={recoveryContext} onChange={e => setRecoveryContext(e.target.value)} placeholder="Context (optional)" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><div className="grid grid-cols-2 gap-3"><select value={recoveryRelationship} onChange={e => setRecoveryRelationship(e.target.value)} className={`px-3 py-2 rounded-lg border text-sm ${c.input}`}><option value="">Talking to...</option>{RELATIONSHIPS.map(r => <option key={r.id} value={r.label}>{r.label}</option>)}</select><select value={recoveryHowBad} onChange={e => setRecoveryHowBad(e.target.value)} className={`px-3 py-2 rounded-lg border text-sm ${c.input}`}>{[['minor', '😅 Minor awkward'], ['bad', '😬 Pretty bad'], ['terrible', '🫣 Terrible'], ['catastrophic', '💀 Catastrophic']].map(([v, l]) => <option key={v} value={v}>{l}</option>)}</select></div><button onClick={handleRecovery} disabled={loading} className={`w-full py-3 rounded-xl font-bold text-sm bg-red-600 hover:bg-red-500 text-white disabled:opacity-50`}>{loading ? <span className="inline-block animate-spin">{tool?.icon ?? '⚙️'}</span> : '🆘 Get Recovery'}</button></div>}{recoveryResults && (() => { const r = recoveryResults; return <div className="space-y-4">{r.damage_check && <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-2`}><div className="flex items-center gap-3"><span className={`text-3xl font-bold ${r.damage_check.how_bad_really <= 3 ? (isDark ? 'text-green-300' : 'text-green-600') : r.damage_check.how_bad_really <= 6 ? (isDark ? 'text-amber-300' : 'text-amber-600') : (isDark ? 'text-red-300' : 'text-red-600')}`}>{r.damage_check.how_bad_really}/10</span><div><h3 className={`font-bold ${c.text}`}>Damage Check</h3><p className={`text-sm ${c.textSecondaryondary}`}>{r.damage_check.immediate_read}</p></div></div><p className={`text-xs ${c.textMuteded}`}>💭 They probably thought: {r.damage_check.what_they_probably_thought}</p></div>}{r.recovery_options?.map((opt, i) => <div key={i} className={`${c.card} border ${c.border} rounded-xl p-4 space-y-2`}><div className="flex items-center gap-2"><span className={`text-xs font-bold px-2 py-0.5 rounded-full ${isDark ? 'bg-cyan-900/30 text-cyan-300' : 'bg-cyan-100 text-cyan-700'}`}>{opt.strategy}</span><span className={`text-xs ${c.textMuteded}`}>⏱️ {opt.timing}</span></div><ConvoLine label="Say this" emoji="🗣️" text={opt.line} accent /><p className={`text-xs ${c.textMuteded}`}>{opt.when_to_use}</p></div>)}{r.do_not_do && <div className={`${c.danger} border rounded-xl p-4`}><p className="text-sm">🚫 <strong>Don't:</strong> {r.do_not_do}</p></div>}{r.body_language && <p className={`text-sm ${c.textSecondaryondary}`}>🧍 {r.body_language}</p>}{r.perspective && <div className={`${c.success} border rounded-xl p-4`}><p className="text-sm">💚 {r.perspective}</p></div>}</div>; })()}</>}

      {/* ═══ PERSON PREP + TRACKER ═══ */}
      {mode === 'person' && <>{<InputCard title="👤 Person Prep" subtitle="Prep for one specific person." onSubmit={handlePersonPrep} btnLabel="Generate Strategy" btnIcon="👤"><div className="grid grid-cols-1 sm:grid-cols-2 gap-3"><input value={personName} onChange={e => setPersonName(e.target.value)} placeholder="Their name (optional)" className={`px-3 py-2 rounded-lg border text-sm ${c.input}`} /><select value={personRelationship} onChange={e => setPersonRelationship(e.target.value)} className={`px-3 py-2 rounded-lg border text-sm ${c.input}`}><option value="">Relationship...</option>{RELATIONSHIPS.map(r => <option key={r.id} value={r.label}>{r.label}</option>)}</select></div><textarea value={personKnow} onChange={e => setPersonKnow(e.target.value)} placeholder="What do you know about them?" rows={3} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={personContext} onChange={e => setPersonContext(e.target.value)} placeholder="Where will you see them?" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={personConcern} onChange={e => setPersonConcern(e.target.value)} placeholder="What worries you? (optional)" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /></InputCard>}
        {/* Recurring Person Tracker */}
        {trackedPeople.length > 0 && <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-3`}><h3 className={`font-bold ${c.text}`}>🔄 Recurring People</h3><p className={`text-xs ${c.textMuteded}`}>Log interactions, then get fresh strategies based on history.</p>{trackedPeople.map((tp, tpIdx) => <div key={tpIdx} className={`${c.cardAlt} border ${c.border} rounded-lg p-4 space-y-2`}><div className="flex items-center justify-between"><div><p className={`text-sm font-bold ${c.text}`}>{tp.name} <span className={`text-xs ${c.textMuteded}`}>({tp.relationship}) · {tp.notes.length} interactions</span></p></div><button onClick={() => setSelectedTrackedPerson(selectedTrackedPerson === tpIdx ? null : tpIdx)} className={`text-xs ${c.accentTxt}`}>{selectedTrackedPerson === tpIdx ? '▲' : '▼'}</button></div>{selectedTrackedPerson === tpIdx && <div className="space-y-2"><div className="grid grid-cols-1 sm:grid-cols-3 gap-2"><input value={personNoteTopics} onChange={e => setPersonNoteTopics(e.target.value)} placeholder="Topics that worked" className={`px-2 py-1.5 rounded-lg border text-xs ${c.input}`} /><input value={personNoteBombed} onChange={e => setPersonNoteBombed(e.target.value)} placeholder="Topics that bombed" className={`px-2 py-1.5 rounded-lg border text-xs ${c.input}`} /><input value={personNoteText} onChange={e => setPersonNoteText(e.target.value)} placeholder="Notes" className={`px-2 py-1.5 rounded-lg border text-xs ${c.input}`} /></div><div className="flex gap-2"><button onClick={() => addPersonNote(tpIdx)} className={`px-3 py-1.5 rounded-lg text-xs font-bold ${c.btnSecondaryondary}`}>📝 Log</button>{tp.notes.length > 0 && <button onClick={() => handlePersonRefresh(tp)} disabled={loading} className={`px-3 py-1.5 rounded-lg text-xs font-bold ${c.btnPrimary} disabled:opacity-50`}>{loading ? <span className="inline-block animate-spin">{tool?.icon ?? '⚙️'}</span> : '🔄 Fresh Strategy'}</button>}</div>{tp.notes.slice(0, 5).map((n, ni) => <p key={ni} className={`text-xs ${c.textMuteded}`}>[{n.date}] ✅ {n.topicsWorked || '—'} | ❌ {n.topicsBombed || '—'}{n.notes ? ` | ${n.notes}` : ''}</p>)}</div>}</div>)}</div>}
        {personName.trim() && !trackedPeople.find(p => p.name === personName) && <button onClick={() => addTrackedPerson(personName, personRelationship)} className={`w-full py-2 rounded-lg text-xs font-bold ${c.btnSecondaryondary} border ${c.border}`}>🔄 Track "{personName}" for recurring encounters</button>}
        {/* Person Refresh Results */}
        {personRefreshResults && <div className="space-y-4">{personRefreshResults.relationship_arc && <div className={`${c.warningBox} border rounded-xl p-5`}><h3 className={`font-bold ${c.accentTxt}`}>📈 Relationship Arc</h3><p className={`text-sm ${c.text} mt-1`}>{personRefreshResults.relationship_arc}</p></div>}{personRefreshResults.pattern_insights?.map((ins, i) => <p key={i} className={`text-sm ${c.textSecondaryondary}`}>💡 {ins}</p>)}{personRefreshResults.fresh_openers?.map((o, i) => <div key={i} className={`${c.cardAlt} rounded-lg p-3`}><ConvoLine label="Fresh opener" emoji="🗣️" text={o.line} accent /><p className={`text-xs ${c.textMuteded}`}>{o.why_now}</p></div>)}{personRefreshResults.wildcard && <div className={`${c.purpleBg} border rounded-xl p-4`}><p className="text-sm">🎲 <strong>Wildcard:</strong> {personRefreshResults.wildcard.move} ({personRefreshResults.wildcard.risk} risk)</p></div>}</div>}
        {/* Person Prep Results (v2 preserved) */}
        {personResults && <div className="space-y-4"><button onClick={() => saveGamePlan(`${personName || personRelationship || 'Person'}`, personResults)} className={`w-full py-2 rounded-lg text-xs font-bold ${c.btnSecondaryondary} border ${c.border}`}>📋 Save Plan</button>{personResults.person_read && <div className={`${c.warningBox} border rounded-xl p-5 space-y-2`}><h3 className={`font-bold ${c.accentTxt}`}>🧠 Reading: {personName || 'Them'}</h3><p className={`text-sm ${c.text}`}>{personResults.person_read.likely_personality}</p><div className={`${c.infoBox} border rounded-lg p-3`}><p className="text-sm">💭 {personResults.person_read.what_they_probably_want}</p></div><div className={`${c.success} border rounded-lg p-3`}><p className="text-sm">✨ {personResults.person_read.your_advantage}</p></div></div>}{personResults.openers?.map((s, i) => <StarterCard key={i} s={s} i={`p-${i}`} saveCtx={personName || personRelationship} />)}{personResults.topics_that_work?.map((t, i) => <div key={i} className={`${c.cardAlt} rounded-lg p-3`}><p className={`text-sm font-bold ${c.text}`}>{t.topic}</p><p className={`text-xs ${c.textSecondaryondary}`}>📝 "{t.entry_point}"</p></div>)}{personResults.overall_strategy && <div className={`${c.purpleBg} border rounded-xl p-5`}><p className="text-sm">{personResults.overall_strategy}</p></div>}</div>}
      </>}

      {/* ═══ GROUP ═══ */}
      {mode === 'group' && <>{<InputCard title="👥 Group Dynamics" subtitle="Groups play by different rules." onSubmit={handleGroup} btnLabel="Analyze Group" btnIcon="👥"><textarea value={groupSituation} onChange={e => setGroupSituation(e.target.value)} placeholder="Describe the group situation" rows={2} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><div className="grid grid-cols-2 gap-3"><select value={groupSize} onChange={e => setGroupSize(e.target.value)} className={`px-3 py-2 rounded-lg border text-sm ${c.input}`}>{['3', '4-6', '7-10', '10+'].map(v => <option key={v} value={v}>{v} people</option>)}</select><input value={groupRole} onChange={e => setGroupRole(e.target.value)} placeholder="Your role (new hire, plus-one)" className={`px-3 py-2 rounded-lg border text-sm ${c.input}`} /></div><input value={groupChallenge} onChange={e => setGroupChallenge(e.target.value)} placeholder="Specific challenge?" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /></InputCard>}{groupResults && <div className="space-y-4">{groupResults.group_read && <div className={`${c.warningBox} border rounded-xl p-5 space-y-2`}><h3 className={`font-bold ${c.accentTxt}`}>🧠 Group Read</h3><p className={`text-sm ${c.text}`}>{groupResults.group_read.dynamics}</p><div className={`${c.success} border rounded-lg p-3`}><p className="text-sm">✨ {groupResults.group_read.your_position}</p></div><div className={`${c.infoBox} border rounded-lg p-3`}><p className="text-sm">💡 {groupResults.group_read.misconception}</p></div></div>}{groupResults.entering_conversations?.map((e, i) => <div key={i} className={`${c.cardAlt} border ${c.border} rounded-lg p-4 space-y-2`}><p className={`text-xs font-bold ${c.textMuteded}`}>{e.scenario}</p><p className={`text-sm ${c.textSecondaryondary}`}>🎯 {e.technique}</p><ConvoLine label="Say" emoji="🗣️" text={e.line} accent onSave={(t) => saveLine(t, 'group')} /></div>)}{groupResults.power_moves?.map((m, i) => { const ec = ENERGY_COLORS[m.energy] || ENERGY_COLORS.confident; return <div key={i} className={`${c.cardAlt} rounded-lg p-3`}><span className={`text-xs font-bold px-2 py-0.5 rounded-full ${isDark ? ec[0] : ec[1]}`}>{m.energy}</span><p className={`text-sm font-bold ${c.text} mt-1`}>{m.move}</p><p className={`text-xs ${c.textSecondaryondary}`}>{m.how}</p></div>; })}{groupResults.if_youre_being_ignored && <div className={`${c.danger} border rounded-xl p-4 space-y-1`}><strong className="text-sm">🫥 If Ignored</strong><p className="text-sm">⚡ {groupResults.if_youre_being_ignored.immediate_fix}</p><p className="text-sm">🧍 {groupResults.if_youre_being_ignored.positioning_fix}</p></div>}</div>}</>}

      {/* ═══ ENERGY MATCH (v3) ═══ */}
      {mode === 'energy' && <>{<InputCard title="🔋 Energy Match" subtitle="When your energy doesn't match the room." onSubmit={handleEnergy} btnLabel="Bridge the Gap" btnIcon="🔋"><div className="grid grid-cols-2 gap-3"><div><label className={`text-xs ${c.label}`}>Your energy</label><select value={myEnergy} onChange={e => setMyEnergy(e.target.value)} className={`w-full mt-1 px-3 py-2 rounded-lg border text-sm ${c.input}`}><option value="">Select...</option>{['Drained / low', 'Quiet / introspective', 'Calm / neutral', 'Upbeat', 'High energy / wired', 'Anxious / jittery'].map(v => <option key={v} value={v}>{v}</option>)}</select></div><div><label className={`text-xs ${c.label}`}>Room's energy</label><select value={roomEnergy} onChange={e => setRoomEnergy(e.target.value)} className={`w-full mt-1 px-3 py-2 rounded-lg border text-sm ${c.input}`}><option value="">Select...</option>{['Dead quiet', 'Calm / subdued', 'Normal conversation', 'Lively / laughing', 'Loud party mode', 'Intense / heated'].map(v => <option key={v} value={v}>{v}</option>)}</select></div></div><input value={energyContext} onChange={e => setEnergyContext(e.target.value)} placeholder="Context (optional)" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /></InputCard>}{energyResults && <div className="space-y-4">{energyResults.gap_read && <div className={`${c.warningBox} border rounded-xl p-5`}><p className={`text-sm ${c.text}`}>{energyResults.gap_read}</p></div>}{energyResults.match_up && <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-2`}><h3 className={`font-bold ${c.text}`}>⬆️ Match Up</h3><p className={`text-sm ${c.textSecondaryondary}`}>{energyResults.match_up.strategy}</p><ConvoLine label="Starter" emoji="🗣️" text={energyResults.match_up.starter_line} accent /></div>}{energyResults.stay_yourself && <div className={`${c.purpleBg} border rounded-xl p-5 space-y-2`}><h3 className="font-bold">🧘 Stay Yourself</h3><p className="text-sm">{energyResults.stay_yourself.strategy}</p><p className="text-sm">{energyResults.stay_yourself.permission}</p></div>}{energyResults.body_hacks?.map((h, i) => <p key={i} className={`text-sm ${c.textSecondaryondary}`}>⚡ {h}</p>)}{energyResults.find_your_people && <div className={`${c.success} border rounded-xl p-4`}><p className="text-sm">👥 {energyResults.find_your_people}</p></div>}{energyResults.reframe && <div className={`${c.infoBox} border rounded-xl p-4`}><p className="text-sm">💚 {energyResults.reframe}</p></div>}</div>}</>}

      {/* ═══ SMALL TALK LADDER (v3) ═══ */}
      {mode === 'ladder' && <>{<InputCard title="🪜 Small Talk Ladder" subtitle="Go from 'nice weather' to genuine connection." onSubmit={handleLadder} btnLabel="Build Ladder" btnIcon="🪜"><select value={ladderRelationship} onChange={e => setLadderRelationship(e.target.value)} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`}><option value="">Relationship type...</option>{RELATIONSHIPS.map(r => <option key={r.id} value={r.label}>{r.label}</option>)}</select><input value={ladderContext} onChange={e => setLadderContext(e.target.value)} placeholder="Context (optional — 'work lunch', 'neighborhood BBQ')" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><select value={ladderDepth} onChange={e => setLadderDepth(e.target.value)} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`}><option value="">Where are you stuck?</option>{['Surface — weather, sports, basic facts', 'Shared experience — but can\'t go deeper', 'Opinions — but it feels risky', 'Personal — but I don\'t want to overshare'].map(v => <option key={v} value={v}>{v}</option>)}</select></InputCard>}{ladderResults && <div className="space-y-4">{ladderResults.ladder?.map((level, i) => <div key={i} className={`${c.card} border ${c.border} rounded-xl p-5 space-y-2`}><div className="flex items-center gap-2"><span className={`text-lg font-bold ${c.accentTxt}`}>{level.level}</span><h3 className={`font-bold ${c.text}`}>{level.name}</h3></div><p className={`text-sm ${c.textSecondaryondary}`}>{level.description}</p>{level.example_topics?.length > 0 && <div className="flex flex-wrap gap-1">{level.example_topics.map((t, j) => <span key={j} className={`text-xs px-2 py-0.5 rounded-full ${isDark ? 'bg-cyan-900/30 text-cyan-300' : 'bg-cyan-100 text-cyan-700'}`}>{t}</span>)}</div>}{level.transition_up && <div className={`${c.warningBox} border rounded-lg p-3 mt-2`}><p className={`text-xs font-bold ${c.accentTxt}`}>⬆️ Go deeper:</p><p className={`text-sm font-semibold ${c.text}`}>"{level.transition_up.phrase}"</p><p className={`text-xs ${c.textMuteded} mt-1`}>📖 {level.transition_up.technique}</p><p className={`text-xs ${c.textMuteded}`}>👀 Ready signal: {level.transition_up.signal_theyre_ready}</p></div>}</div>)}{ladderResults.stuck_at_surface && <div className={`${c.warning} border rounded-xl p-5 space-y-2`}><h3 className="font-bold text-sm">🔒 Stuck at Surface?</h3><p className="text-sm">{ladderResults.stuck_at_surface.the_fix}</p><ConvoLine label="Magic question" emoji="✨" text={ladderResults.stuck_at_surface.magic_question} accent /></div>}{ladderResults.too_deep_too_fast && <div className={`${c.danger} border rounded-xl p-4`}><p className="text-sm">⚠️ <strong>Too deep too fast?</strong> {ladderResults.too_deep_too_fast.signs}</p><p className="text-sm mt-1">🔄 {ladderResults.too_deep_too_fast.recovery}</p></div>}{ladderResults.the_goal && <div className={`${c.success} border rounded-xl p-4`}><p className="text-sm">🎯 {ladderResults.the_goal}</p></div>}</div>}</>}

      {/* ═══ CULTURE DECODER (v3) ═══ */}
      {mode === 'culture' && <>{<InputCard title="🌍 Culture Decoder" subtitle="Navigate cross-cultural social situations." onSubmit={handleCulture} btnLabel="Decode Culture" btnIcon="🌍"><input value={cultureText} onChange={e => setCultureText(e.target.value)} placeholder="Culture or background ('Japanese business culture', 'Indian wedding')" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={cultureSituation} onChange={e => setCultureSituation(e.target.value)} placeholder="Situation ('business dinner', 'meeting partner's family')" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={cultureMyBg} onChange={e => setCultureMyBg(e.target.value)} placeholder="Your background (optional)" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={cultureConcern} onChange={e => setCultureConcern(e.target.value)} placeholder="Specific concern (optional)" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /></InputCard>}{cultureResults && (() => { const r = cultureResults; return <div className="space-y-4">{r.quick_read && <div className={`${c.warningBox} border rounded-xl p-5 space-y-2`}><h3 className={`font-bold ${c.accentTxt}`}>🌍 Quick Read</h3><p className={`text-sm ${c.text}`}>⚡ {r.quick_read.biggest_difference}</p><p className={`text-sm ${c.textSecondaryondary}`}>✅ {r.quick_read.good_news}</p><div className={`${c.warning} border rounded-lg p-3`}><p className="text-sm">🔑 {r.quick_read.hidden_rule}</p></div></div>}{r.do_this?.map((d, i) => <div key={i} className={`${c.success} border rounded-lg p-3`}><p className={`text-sm font-bold`}>✅ {d.norm}</p><p className="text-xs">{d.how}</p><p className={`text-xs ${c.textMuteded}`}>{d.why}</p></div>)}{r.avoid_this?.map((a, i) => <div key={i} className={`${c.danger} border rounded-lg p-3`}><p className="text-sm font-bold">❌ {a.mistake}</p><p className="text-xs">{a.why_its_bad}</p><p className={`text-xs ${c.accentTxt}`}>✅ Instead: {a.what_to_do_instead}</p></div>)}{r.body_language && <Section id="culturebody" title="🧍 Body Language"><p className="text-sm">🤝 {r.body_language.greetings}</p><p className="text-sm">👁️ {r.body_language.eye_contact}</p>{r.body_language.gestures_to_avoid?.map((g, i) => <p key={i} className="text-sm">⚠️ {g}</p>)}</Section>}{r.conversation && <Section id="cultureconv" title="💬 Conversation">{r.conversation.safe_topics?.map((t, i) => <span key={i} className={`inline-block text-xs px-2 py-0.5 rounded-full mr-1 mb-1 ${isDark ? 'bg-green-900/30 text-green-300' : 'bg-green-100 text-green-700'}`}>✅ {t}</span>)}{r.conversation.dangerous_topics?.map((t, i) => <span key={i} className={`inline-block text-xs px-2 py-0.5 rounded-full mr-1 mb-1 ${isDark ? 'bg-red-900/30 text-red-300' : 'bg-red-100 text-red-700'}`}>❌ {t}</span>)}<p className={`text-sm ${c.textSecondaryondary} mt-2`}>😄 {r.conversation.humor}</p></Section>}{r.phrase_to_know && <div className={`${c.infoBox} border rounded-xl p-4`}><p className="text-sm">🗣️ <strong>Learn this:</strong> {r.phrase_to_know}</p><CopyBtn content={r.phrase_to_know + BRAND} label="Copy" /></div>}{r.graceful_recovery && <div className={`${c.warning} border rounded-xl p-4`}><p className="text-sm">🔄 <strong>If you mess up:</strong> {r.graceful_recovery}</p></div>}</div>; })()}</>}

      {/* ═══ DECODER ═══ */}
      {mode === 'decode' && <>{<InputCard title="🔍 Signal Decoder" subtitle="Something happened and you're not sure what it meant?" onSubmit={handleDecode} btnLabel="Decode This" btnIcon="🔍"><textarea value={theyDid} onChange={e => setTheyDid(e.target.value)} placeholder="What did they say or do?" rows={3} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={decodeContext} onChange={e => setDecodeContext(e.target.value)} placeholder="Context (optional)" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><div className="grid grid-cols-2 gap-3"><select value={decodeRelationship} onChange={e => setDecodeRelationship(e.target.value)} className={`px-3 py-2 rounded-lg border text-sm ${c.input}`}><option value="">Relationship...</option>{RELATIONSHIPS.map(r => <option key={r.id} value={r.label}>{r.label}</option>)}</select><input value={yourConcern} onChange={e => setYourConcern(e.target.value)} placeholder="What I'm worried it means" className={`px-3 py-2 rounded-lg border text-sm ${c.input}`} /></div></InputCard>}{decodeResults && <div className="space-y-4">{decodeResults.most_likely && <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-2`}><h3 className={`font-bold ${c.text}`}>🎯 Most Likely</h3><div className={`inline-block text-xs font-bold px-2 py-0.5 rounded-full ${decodeResults.most_likely.confidence === 'pretty sure' ? (isDark ? 'bg-green-900/30 text-green-300' : 'bg-green-100 text-green-700') : (isDark ? 'bg-amber-900/30 text-amber-300' : 'bg-amber-100 text-amber-700')}`}>{decodeResults.most_likely.confidence}</div><p className={`text-sm ${c.text}`}>{decodeResults.most_likely.read}</p></div>}{decodeResults.overthinking_check && <div className={`${c.infoBox} border rounded-xl p-4`}><p className="text-sm">🧠 {decodeResults.overthinking_check}</p></div>}{decodeResults.what_to_do && <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-3`}><h3 className={`font-bold ${c.text}`}>🛤️ Options</h3>{decodeResults.what_to_do.if_you_want_to_address_it && <div className={`${c.warningBox} border rounded-lg p-3`}><p className={`text-xs font-bold ${c.accentTxt}`}>Address it:</p><p className={`text-sm ${c.text}`}>{decodeResults.what_to_do.if_you_want_to_address_it}</p></div>}{decodeResults.what_to_do.if_you_want_to_let_it_go && <div className={`${c.quoteBg} border rounded-lg p-3`}><p className={`text-xs font-bold ${c.textMuteded}`}>Let it go:</p><p className={`text-sm ${c.textSecondaryondary}`}>{decodeResults.what_to_do.if_you_want_to_let_it_go}</p></div>}</div>}{decodeResults.reframe && <div className={`${c.success} border rounded-xl p-4`}><p className="text-sm">💚 {decodeResults.reframe}</p></div>}</div>}</>}

      {/* ═══ FOLLOW-UP ═══ */}
      {mode === 'followup' && <>{<InputCard title="💬 Follow-Up Message" subtitle="The 'what do I text them?' moment." onSubmit={handleFollowUp} btnLabel="Draft Follow-Up" btnIcon="💬"><div className="grid grid-cols-2 gap-3"><input value={followUpWho} onChange={e => setFollowUpWho(e.target.value)} placeholder="Who?" className={`px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={followUpContext} onChange={e => setFollowUpContext(e.target.value)} placeholder="Context" className={`px-3 py-2 rounded-lg border text-sm ${c.input}`} /></div><textarea value={followUpWhat} onChange={e => setFollowUpWhat(e.target.value)} placeholder="What happened? (optional)" rows={2} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={followUpGoal} onChange={e => setFollowUpGoal(e.target.value)} placeholder="Your goal?" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /></InputCard>}{followUpResults && <div className="space-y-4">{followUpResults.timing && <div className={`${c.infoBox} border rounded-xl p-4`}><p className="text-sm">⏰ {followUpResults.timing}</p></div>}{followUpResults.messages?.map((m, i) => <div key={i} className={`${c.card} border ${c.border} rounded-xl p-5 space-y-2`}><div className="flex items-center gap-2"><span className={`text-xs font-bold px-2 py-0.5 rounded-full ${isDark ? 'bg-cyan-900/30 text-cyan-300' : 'bg-cyan-100 text-cyan-700'}`}>{m.style}</span><span className={`text-xs px-2 py-0.5 rounded-full border ${m.risk === 'low' ? c.success : m.risk === 'high' ? c.danger : c.warning}`}>{m.risk}</span></div><div className={`${c.warningBox} border rounded-lg p-4`}><p className={`text-sm ${c.text}`}>{m.text}</p></div><CopyBtn content={m.text + BRAND} label="Copy" /></div>)}{followUpResults.do_not_send && <div className={`${c.danger} border rounded-xl p-4`}><p className="text-sm">🚫 {followUpResults.do_not_send}</p></div>}</div>}</>}

      {/* ═══ DEBRIEF ═══ */}
      {mode === 'debrief' && <>{<InputCard title="📝 Debrief" subtitle="Wins auto-add to your Playbook." onSubmit={handleDebrief} btnLabel="Debrief" btnIcon="📝"><input value={debriefEvent} onChange={e => setDebriefEvent(e.target.value)} placeholder="What was the event?" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><textarea value={debriefWhat} onChange={e => setDebriefWhat(e.target.value)} placeholder="What happened?" rows={2} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><textarea value={debriefGood} onChange={e => setDebriefGood(e.target.value)} placeholder="What went well?" rows={2} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><textarea value={debriefAwkward} onChange={e => setDebriefAwkward(e.target.value)} placeholder="What felt awkward? (optional)" rows={2} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><div className="flex flex-wrap gap-2">{[['great', '🎉', 'Great!'], ['good', '😊', 'Good'], ['mixed', '😐', 'Mixed'], ['rough', '😓', 'Rough']].map(([v, ico, lbl]) => <button key={v} onClick={() => setDebriefFeeling(v)} className={`px-3 py-1.5 rounded-lg text-xs font-medium border ${debriefFeeling === v ? c.btnActive : `${c.btnInactive} ${c.border}`}`}><span className="mr-1">{ico}</span> {lbl}</button>)}</div></InputCard>}{debriefResults && <div className="space-y-4">{debriefResults.honest_read && <div className={`${c.warningBox} border rounded-xl p-5`}><p className={`text-sm ${c.text}`}>{debriefResults.honest_read}</p></div>}{debriefResults.wins?.map((w, i) => <div key={i} className={`${c.success} border rounded-lg p-3`}><p className="text-sm">✅ {w.what}</p><p className="text-xs">{w.why_it_worked}</p>{w.add_to_playbook && <p className={`text-xs ${c.accentTxt}`}>📚 Playbook: {w.add_to_playbook}</p>}</div>)}{debriefResults.awkward_reframes?.map((a, i) => <div key={i} className={`${c.cardAlt} rounded-lg p-3`}><p className={`text-sm ${c.text}`}>😬 {a.what_felt_bad}</p><p className={`text-sm ${c.textSecondaryondary}`}>👁️ {a.reality_check}</p></div>)}{debriefResults.next_challenge && <div className={`${c.purpleBg} border rounded-xl p-4`}><p className="text-sm font-bold">🎯 Next: {debriefResults.next_challenge.suggestion}</p><p className="text-xs">{debriefResults.next_challenge.why}</p></div>}</div>}</>}

      {/* ═══ SOCIAL AUTOPSY (v3) ═══ */}
      {mode === 'autopsy' && <>{<InputCard title="🔬 Social Autopsy" subtitle="Deep forensic analysis. What went wrong and why." onSubmit={handleAutopsy} btnLabel="Analyze" btnIcon="🔬"><textarea value={autopsyWhat} onChange={e => setAutopsyWhat(e.target.value)} placeholder="What happened? Tell the whole story." rows={4} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><textarea value={autopsyTimeline} onChange={e => setAutopsyTimeline(e.target.value)} placeholder="Timeline / arc (optional — 'started fine, got weird after 20 min')" rows={2} className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={autopsyFelt} onChange={e => setAutopsyFelt(e.target.value)} placeholder="How did you feel?" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /><input value={autopsyThink} onChange={e => setAutopsyThink(e.target.value)} placeholder="What do you think went wrong?" className={`w-full px-3 py-2 rounded-lg border text-sm ${c.input}`} /></InputCard>}{autopsyResults && (() => { const r = autopsyResults; return <div className="space-y-4">{r.honest_assessment && <div className={`${c.warningBox} border rounded-xl p-5`}><h3 className={`font-bold ${c.accentTxt}`}>📋 Honest Assessment</h3><p className={`text-sm ${c.text} mt-2`}>{r.honest_assessment}</p></div>}{r.turning_point && <div className={`${c.card} border ${c.border} rounded-xl p-5 space-y-2`}><h3 className={`font-bold ${c.text}`}>📍 Turning Point</h3><p className={`text-sm ${c.textSecondaryondary}`}>{r.turning_point.moment}</p><p className={`text-sm ${c.text}`}>{r.turning_point.what_caused_it}</p><div className={`inline-block text-xs font-bold px-2 py-0.5 rounded-full ${r.turning_point.was_it_you?.toLowerCase().includes('not') || r.turning_point.was_it_you?.toLowerCase().includes('outside') ? c.success : r.turning_point.was_it_you?.toLowerCase().includes('both') ? c.warning : c.infoBox}`}>{r.turning_point.was_it_you}</div></div>}{r.signals_you_missed?.map((s, i) => <div key={i} className={`${c.warning} border rounded-lg p-3`}><p className="text-sm">👀 {s.signal}</p><p className="text-xs">{s.what_it_meant}</p><p className={`text-xs ${c.accentTxt}`}>Next time: {s.how_to_spot_it_next_time}</p></div>)}{r.what_was_not_your_fault?.length > 0 && <div className={`${c.success} border rounded-xl p-5 space-y-1`}><h3 className="font-bold text-sm">🛡️ Not Your Fault</h3>{r.what_was_not_your_fault.map((n, i) => <p key={i} className="text-sm">• {n}</p>)}</div>}{r.what_was_in_your_control?.length > 0 && <div className={`${c.infoBox} border rounded-xl p-5 space-y-1`}><h3 className="font-bold text-sm">🎮 In Your Control</h3>{r.what_was_in_your_control.map((n, i) => <p key={i} className="text-sm">• {n}</p>)}</div>}{r.the_real_lesson && <div className={`${c.purpleBg} border rounded-xl p-4`}><p className="text-sm font-bold">📖 The Real Lesson</p><p className="text-sm mt-1">{r.the_real_lesson}</p></div>}{r.next_time?.add_to_playbook && <p className={`text-xs ${c.accentTxt}`}>📚 Added to playbook: {r.next_time.add_to_playbook}</p>}{r.compassion_note && <div className={`${c.success} border rounded-xl p-5`}><p className={`text-sm font-medium ${isDark ? 'text-green-200' : 'text-green-800'}`}>💚 {r.compassion_note}</p></div>}</div>; })()}</>}

      {/* ─── Error ─── */}
      {error && <div className={`${c.danger} border rounded-xl p-4 text-sm`}>⚠️ {error}</div>}

      {/* ─── Cross-References ─── */}
      {(preGameResults || quickResults || decodeResults || followUpResults || debriefResults || personResults || groupResults || recoveryResults || cultureResults || autopsyResults || ladderResults || energyResults) && <div className={`${c.cardAlt} border ${c.border} rounded-xl p-4`}><p className={`text-xs ${c.textMuteded} mb-2`}>Related tools:</p><div className="flex flex-wrap gap-2">{[['ConfrontationCoach', '🥊', 'tough conversations'], ['ApologyCalibrator', '🙏', 'craft apologies'], ['DoubleBookingDiplomat', '📅', 'cancel gracefully'], ['CaptionMagic', '✍️', 'social captions']].map(([id, ico, desc]) => <a key={id} href={`/${id}`} target="_blank" rel="noopener noreferrer" className={`text-xs px-3 py-1.5 rounded-lg ${c.btnSecondaryondary} no-underline`}>{ico} {desc}</a>)}</div></div>}

      {/* ─── History ─── */}
      {history.length > 0 && <div className={`${c.card} border ${c.border} rounded-xl p-5`}><button onClick={() => toggleSection('history')} className="flex items-center justify-between w-full"><h3 className={`font-bold ${c.text}`}>📜 Recent ({history.length})</h3><span>{expandedSections.history ? '▲' : '▼'}</span></button>{expandedSections.history && <div className="mt-3 space-y-1">{history.slice(0, 20).map((h, i) => <div key={i} className={`${c.cardAlt} rounded-lg p-2 flex items-center justify-between`}><span className={`text-sm ${c.textSecondaryondary}`}>{MODES.find(m => m.id === h.type)?.icon || '🧠'} {h.label}</span><span className={`text-xs ${c.textMuteded}`}>{new Date(h.timestamp).toLocaleDateString()}</span></div>)}<button onClick={() => setHistory([])} className={`text-xs ${c.textMuteded}`}>🗑️ Clear</button></div>}</div>}

      {/* eslint-disable-next-line no-restricted-globals */}
      {history.length > 0 && (<div className={`${c.cardAlt} border ${c.border} rounded-xl p-4 mt-4`}><p className={`text-xs font-bold ${c.textMuted} mb-2`}>📋 Recent</p><div className="space-y-1">{history.map(s => (<div key={s.id} className="flex items-center justify-between"><span className={`text-xs ${c.textSecondary} truncate`}>{s.preview||'Session'}</span><span className={`text-xs ${c.textMuted} ml-2`}>{new Date(s.date).toLocaleDateString()}</span></div>))}</div></div>)}
      <div className={`${c.cardAlt} border ${c.border} rounded-xl p-4 mt-4`}><p className={`text-xs font-bold ${c.textMuted} mb-2`}>🔗 Related tools</p><div className="flex flex-wrap gap-3"><a href="/tool/decision-coach" className={`text-xs ${linkStyle}`}>🎯 Decision Coach</a><a href="/tool/spiral-stopper" className={`text-xs ${linkStyle}`}>🌀 Spiral Stopper</a></div></div>
    </div>
  );
};

RoomReader.displayName = 'RoomReader';
export default RoomReader;
